var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 아까부터 왜 그렇게 조용해?","JPN":"なあ、さっきからやけに静かじゃないか。","ENG":"Why are you so quiet, kid?","TWN":"小鬼，你怎麼一直不說話？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나한테 할 말이 많지 않아?","JPN":"何か言いたいことがあるんじゃないのか？","ENG":"Don't you have something to say to me?","TWN":"你不是有很多話要對我說嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그게...... 리타 언니는 제가 떠들면 싫어하니까요.","JPN":"それは……リタお姉ちゃんは私がうるさくおしゃべりすると嫌がるから……","ENG":"Well... You don't like it when I get chatty.","TWN":"那個……因為麗塔姐姐不喜歡我吵鬧嘛。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"언제는 내 말 듣고 얌전히 있던 것처럼 말하는군.","JPN":"いつもは私に言われたとおり大人しくしているような言い方だな。","ENG":"Since when did that stop you?","TWN":"說的好像你之前很聽話一樣。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"말해. 뭐가 문제야.","JPN":"さっさと言え。何が問題だ？","ENG":"Go ahead. What's bothering you?","TWN":"說吧，有什麼問題。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아뇨. 문제 같은 거 없어요.","JPN":"いいえ。問題なんかありませんよ。","ENG":"Nothing. It's nothing, really.","TWN":"沒有，沒有問題。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저는 그냥 리타 언니 소유물이니까...... 앞으로 얌전히 굴려고......","JPN":"私はお姉ちゃんの所有物にすぎないから……これから大人しくしてようと……","ENG":"Since I'm your property... I'm just going to be nice and quiet from now on...","TWN":"我只是麗塔姐姐的抵押品……以後我會老老實實的……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 언니? 왜 그래요, 갑자기......?","JPN":"リ、リタお姉ちゃん？　どうしたんですか、急に……？","ENG":"R-Rita? What's wrong?","TWN":"姐、姐姐？你、你怎麼了……？"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 말 잘했어.","JPN":"そうだな。よく言ってくれた。","ENG":"Right. Well said.","TWN":"嗯，你說得很好。"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 네 부모들이 고용한 베이비시터가 아냐. 네 소유주지.","JPN":"私はお前の親に雇われたベビーシッターじゃない。お前の所有者なんだ。","ENG":"I'm not some babysitter your parents hired. I'm your owner.","TWN":"我不是你父母雇傭的保姆，而是你的主人。"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런데 넌 내 마음대로 될 때가 없어.","JPN":"なのにお前は私の思い通りになる時がない。","ENG":"But you never do as I say.","TWN":"但你很不聽話。"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"잠깐 눈을 떼면 멋대로 위험에 빠지질 않나, 틈만 나면 다쳐서 오질 않나......","JPN":"少し目を離すと勝手に危険なことに巻き込まれるし、隙あれば怪我をして……","ENG":"The moment I take my eyes off of you, you get yourself into danger, always getting yourself hurt.","TWN":"一不留神就陷入危險，動不動就受傷……"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러고도 화를 안 내길 바라는 게 웃기지.","JPN":"なのに、怒られたくないって？","ENG":"How am I supposed to not get angry at you?","TWN":"你這樣還期望我能夠不生氣嗎？"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"넌 나 따위 안중에도 없어. 그 빌어먹을 집구석만 생각하기 바쁘니까.","JPN":"お前は私のことちっとも考えてないだろ。自分の家族のことばっかりで。","ENG":"You don't give a darn about me. All you care about is that hopeless family of yours.","TWN":"你根本不把我放在眼裡。因為你一心只想著你那個家。"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돌아가고 싶은 거지? 네 부모들한테?","JPN":"帰りたいんだろ？　お前の親のところに。","ENG":"You want to go back to them? Back to your parents?","TWN":"你想回去是吧？回到你父母身邊？"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這……"},"stage":{"bg":"SS_SHADOW_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};